(()=>{"use strict";class t extends HTMLElement{constructor(){super(),this.intervalId=null}connectedCallback(){this.render(),this.start()}disconnectedCallback(){this.stop()}start(){this.intervalId=window.setInterval(()=>{this.render()},1e3)}stop(){null!==this.intervalId&&(clearInterval(this.intervalId),this.intervalId=null)}formatTime(t){return`${String(t.getHours()).padStart(2,"0")}:${String(t.getMinutes()).padStart(2,"0")}:${String(t.getSeconds()).padStart(2,"0")}`}render(){const t=new Date;this.textContent=this.formatTime(t)}}class e extends HTMLElement{constructor(){super(),this.WORDS=["CREATIVE","CRIATIVO","KREATIV","CREATIVITÉ","ΔΗΜΙΟΥΡΓΙΚΟΣ","CREARE"],this.currentWordIndex=0,this.isVisible=!0,this.intervalId=null,this.timeoutId=null}connectedCallback(){this.render(),this.start()}disconnectedCallback(){this.stop()}start(){this.intervalId=window.setInterval(()=>{this.fadeOut(),this.timeoutId=window.setTimeout(()=>{this.nextWord(),this.fadeIn()},800)},4e3)}stop(){this.intervalId&&clearInterval(this.intervalId),this.timeoutId&&clearTimeout(this.timeoutId)}nextWord(){this.currentWordIndex=(this.currentWordIndex+1)%this.WORDS.length,this.updateWord()}fadeOut(){this.isVisible=!1,this.wordEl.style.opacity="0"}fadeIn(){this.isVisible=!0,this.wordEl.style.opacity="1"}updateWord(){this.wordEl.textContent=this.WORDS[this.currentWordIndex]}render(){this.querySelector(".letter").innerHTML=`\n      <div class="hero-word" style="\n        transition: opacity 0.8s ease;\n        opacity: 1;\n      ">\n        ${this.WORDS[this.currentWordIndex]}\n      </div>\n    `,this.wordEl=this.querySelector(".hero-word")}}customElements.get("clock-component")||customElements.define("clock-component",t),customElements.get("hero-section")||customElements.define("hero-section",e)})();